Which one of the choices given below would be printed when the following program is executed?

#include <stdio.h>
struct test {
    int i;
    char *c;
} st[] = {5, "become", 4, "better", 6, "jungle", 8, "ancestor", 7, "brother"};
main() {
    struct test *p = st;
    p += 1;
    ++p -> c;
    printf("%s,", p++ -> c);
    printf("%d,", p -> i);
    printf("%s", p -> c);
}

A. jungle, is, 6, ancestor
B. etter, is, 6, jungle
C. etter, 6, jungle
D. etter, 6, ancestor

